module shift_register(
    input        clk,
    input        reset,
    input        load,
    input [15:0] load_data,
    input        shift_enable,
    output reg [15:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
begin
    if (reset)
        q <= 16'b0;
    else if (load)
        q <= load_data;
    else if (shift_enable)
        q <= {q[14:0], 1'b0};
end

endmodule
